                            {
                                Error = "Invalid operator",
                                Message = $"Operator '{filter.Operator}' is not supported."
                            });
                        }

                        string exactCol = GetExactColumnName(tableName, filter.Column);
                        string quotedCol = $"[{exactCol}]";
                        string paramName = $"@p{paramIndex++}";

