        private static FilterResult ParseFilters(IQueryCollection query, string tableName)
        {
            var conditions = new List<string>();
            var parameters = new List<SqlParameter>();
            int paramIndex = 0;

            // Reserved query string keys that are not filters
            var reservedKeys = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
            {
                "select", "orderby", "sortdir", "pagesize", "offset", "top"
            };

            foreach (var key in query.Keys)
            {
                if (reservedKeys.Contains(key))
                    continue;

                // Parse filter key format: column_operator (e.g., Amount_gt, Region_eq, Name_like)
                string columnName;
                string operatorStr = "eq";

                var parts = key.Split('_');
                if (parts.Length == 2 && AllowedOperators.Contains(parts[1]))
                {
                    columnName = parts[0];
                    operatorStr = parts[1].ToLowerInvariant();
                }
                else if (parts.Length == 1)
                {
                    columnName = parts[0];
                }
                else
                {
                    // Could be column name with underscore - try full key as column name
                    columnName = key;
                }

                if (!AllowedColumns[tableName].Contains(columnName))
                {
                    return new FilterResult
                    {
                        Error = $"Column '{columnName}' is not valid for table '{tableName}'. Valid columns: {string.Join(", ", AllowedColumns[tableName])}"
                    };
                }

                string exactCol = GetExactColumnName(tableName, columnName);
                string quotedCol = $"[{exactCol}]";
                string value = query[key];

                if (operatorStr == "in")
                {
                    var values = value.Split(',');
                    var inParams = new List<string>();
                    foreach (var val in values)
                    {
                        string inParamName = $"@p{paramIndex++}";
                        inParams.Add(inParamName);
                        parameters.Add(new SqlParameter(inParamName, val.Trim()));
                    }
                    if (inParams.Any())
                    {
                        conditions.Add($"{quotedCol} IN ({string.Join(", ", inParams)})");
                    }
                }
                else
                {
                    string sqlOperator = MapOperator(operatorStr);
                    string paramName = $"@p{paramIndex++}";

                    object paramValue;
                    if (operatorStr == "like")
                    {
                        paramValue = $"%{value}%";
                    }
                    else
                    {
                        paramValue = value;
                    }

                    conditions.Add($"{quotedCol} {sqlOperator} {paramName}");
                    parameters.Add(new SqlParameter(paramName, paramValue ?? DBNull.Value));
                }
            }

            return new FilterResult { Conditions = conditions, Parameters = parameters };
        }

        private static SelectResult ParseSelectColumns(IQueryCollection query, string tableName)
        {
            var columns = new List<string>();

            if (query.ContainsKey("select"))
            {
                var requestedColumns = query["select"].ToString().Split(',', StringSplitOptions.RemoveEmptyEntries);
                foreach (var col in requestedColumns)
                {
                    string trimmed = col.Trim();
                    if (!AllowedColumns[tableName].Contains(trimmed))
                    {
                        return new SelectResult
                        {
                            Error = $"Column '{trimmed}' is not valid for table '{tableName}'."
                        };
                    }
                    columns.Add(GetExactColumnName(tableName, trimmed));
                }
            }

            return new SelectResult { Columns = columns };
        }

        private static SortResult ParseSortParameters(IQueryCollection query, string tableName)
        {
            var sortClauses = new List<string>();

            if (query.ContainsKey("orderby"))
            {
                var sortParts = query["orderby"].ToString().Split(',', StringSplitOptions.RemoveEmptyEntries);
                foreach (var part in sortParts)
                {
                    var tokens = part.Trim().Split(' ', StringSplitOptions.RemoveEmptyEntries);
                    string colName = tokens[0];
                    string direction = tokens.Length > 1 ? tokens[1].ToUpperInvariant() : "ASC";

                    if (!AllowedColumns[tableName].Contains(colName))
                    {
                        return new SortResult
                        {
                            Error = $"Sort column '{colName}' is not valid for table '{tableName}'."
                        };
                    }

                    if (!AllowedSortDirections.Contains(direction))
                    {
                        direction = "ASC";
                    }

                    sortClauses.Add($"[{GetExactColumnName(tableName, colName)}] {direction}");
                }
            }

            return new SortResult { SortClauses = sortClauses };
        }

        private static PaginationResult ParsePagination(IQueryCollection query)
        {
            int pageSize = 100;
            int offset = 0;

            if (query.ContainsKey("pagesize"))
            {
                if (!int.TryParse(query["pagesize"], out pageSize) || pageSize < 1)
                {
                    return new PaginationResult { Error = "pagesize must be a positive integer." };
                }
                pageSize = Math.Min(pageSize, 1000); // Max 1000 rows
            }

            if (query.ContainsKey("offset"))
            {
                if (!int.TryParse(query["offset"], out offset) || offset < 0)
                {
                    return new PaginationResult { Error = "offset must be a non-negative integer." };
                }
            }

            return new PaginationResult { PageSize = pageSize, Offset = offset };
        }

        private static async Task<QueryResult> ExecuteQueryAsync(
            string tableName,
            List<string> selectColumns,
            List<string> conditions,
            List<SqlParameter> parameters,
            List<string> sortClauses,
            int offset,
            int pageSize,
            ILogger log)
        {
            string connectionString = Environment.GetEnvironmentVariable("SqlConnectionString");

            // Build SELECT clause using whitelisted column names (already validated)
            string selectClause = selectColumns.Any()
                ? string.Join(", ", selectColumns.Select(c => $"[{c}]"))
                : "*";

            // Table name is from whitelist, so it's safe to use directly
            string quotedTable = $"[dbo].[{tableName}]";

            // Build WHERE clause with parameterized conditions
            string whereClause = conditions.Any()
                ? "WHERE " + string.Join(" AND ", conditions)
                : "";

            // Build ORDER BY clause (columns already validated against whitelist)
            string orderByClause = sortClauses.Any()
                ? "ORDER BY " + string.Join(", ", sortClauses)
                : "ORDER BY (SELECT NULL)";

            // Count query
            string countSql = $"SELECT COUNT(*) FROM {quotedTable} {whereClause}";

            // Data query with pagination
            string dataSql = $@"
                SELECT {selectClause} 
                FROM {quotedTable} 
                {whereClause} 
                {orderByClause} 
                OFFSET @offset ROWS FETCH NEXT @pageSize ROWS ONLY";

            log.LogInformation("Executing query on table {Table} with {FilterCount} filters", tableName, conditions.Count);

            var result = new QueryResult();

            using (var connection = new SqlConnection(connectionString))
            {
                await connection.OpenAsync();

                // Get total count
                using (var countCmd = new SqlCommand(countSql, connection))
                {
                    countCmd.CommandTimeout = 30;
                    // Clone parameters for count query
                    foreach (var param in parameters)
                    {
                        countCmd.Parameters.Add(new SqlParameter(param.ParameterName, param.Value));
                    }
                    result.TotalCount = (int)await countCmd.ExecuteScalarAsync();
                }

                // Get data
                using (var dataCmd = new SqlCommand(dataSql, connection))
                {
                    dataCmd.CommandTimeout = 30;
                    foreach (var param in parameters)
                    {
                        dataCmd.Parameters.Add(new SqlParameter(param.ParameterName, param.Value));
                    }
                    dataCmd.Parameters.Add(new SqlParameter("@offset", offset));
                    dataCmd.Parameters.Add(new SqlParameter("@pageSize", pageSize));

                    using (var reader = await dataCmd.ExecuteReaderAsync())
                    {
                        var rows = new List<Dictionary<string, object>>();
                        while (await reader.ReadAsync())
                        {
                            var row = new Dictionary<string, object>();
                            for (int i = 0; i < reader.FieldCount; i++)
                            {
                                var value = reader.GetValue(i);
                                row[reader.GetName(i)] = value == DBNull.Value ? null : value;
                            }
                            rows.Add(row);
                        }
                        result.Rows = rows;
                    }
                }
            }

            return result;
        }

        private static string GetExactColumnName(string tableName, string inputColumn)
        {
            // Return the exact-cased column name from our whitelist
            if (AllowedColumns.TryGetValue(tableName, out var columns))
            {
                foreach (var col in columns)
                {
                    if (string.Equals(col, inputColumn, StringComparison.OrdinalIgnoreCase))
                        return col;
                }
            }
            return inputColumn;
        }

        private static string MapOperator(string op)
        {
            return op.ToLowerInvariant() switch
            {
                "eq" => "=",
                "neq" => "!=",
                "gt" => ">",
                "gte" => ">=",
                "lt" => "<",
                "lte" => "<=",
                "like" => "LIKE",
                _ => "="
            };
        }
